#!/usr/bin/env python3
"""Build batch_01.csv (rows 1000-1999) from extracted mp/bp data."""
import csv

OUT = '/sessions/wizardly-beautiful-tesla/mnt/opus47_books/batches/batch_01.csv'
HEADER = ['id','verification_status','compound_name','compound_smiles','property','value','value_min','value_max','value_raw','units','relation','meas_calc','source','source_url','evidence_location','evidence_quote','conversion_arithmetic','notes']

ROWS = []

# Helper to make rows
def r(id_, cn, prop, val, vmin, vmax, vraw, rel, source, url, loc, quote, notes=""):
    ROWS.append([str(id_), "pending_verification", cn, "", prop, str(val), str(vmin), str(vmax), vraw, "°C", rel, "measured", source, url, loc, quote, "", notes])

